/*
  # Update Argentina Passport Complete Visa Requirements

  1. Updates for Argentina Passport Holders
    - Fix all destination visa requirements with accurate, fact-checked data
    - Correct insurance requirements (not mandatory at border for visa-free Schengen)
    - Correct return ticket requirements (may be requested at discretion)
    - Add ETIAS information for all Schengen destinations
    - Add eTA/ESTA/K-ETA/NZeTA requirements where applicable
    - Update notes with comprehensive, accurate entry information
    - Set last_verified to 2026-02-19

  2. Key Corrections
    - Australia: eVisitor/ETA required (not simple visa-free)
    - Canada: Visa required (some eligible for eTA)
    - China: Temporary visa-free until Dec 31, 2026 (15 days only)
    - New Zealand: NZeTA required
    - South Korea: K-ETA required
    - UK: ETA required from April 2, 2025
    - USA: ESTA required under VWP
    - All Schengen: Insurance NOT mandatory at border, return ticket may be requested, ETIAS from late 2026

  3. Affected Destinations
    All 42 destinations for Argentina passport holders
*/

-- Australia
UPDATE visa_rules SET visa_type = 'evisa', visa_subtype = 'eVisitor or ETA', max_stay_days = 90, stay_window_days = 365, passport_validity_months = 0, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Argentine citizens must obtain either a free eVisitor visa (subclass 651) or a paid ETA (subclass 601) before travel. No visa stamp issued on arrival. Max stay: 3 months per visit within a 12-month period. Apply online via Australian Department of Home Affairs before departure. Biometric checks conducted on arrival.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'argentina' AND destination_slug = 'australia';

