UPDATE visa_rules SET visa_type = 'evisa', visa_subtype = 'UK ETA', max_stay_days = 180, stay_window_days = null, passport_validity_months = 0, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'UK Electronic Travel Authorisation (ETA) mandatory from April 2, 2025. Apply via UK ETA app or online at gov.uk/guidance/apply-for-an-electronic-travel-authorisation-eta. Fee GBP 16 (approx. USD 20). Valid 2 years or until passport expiry. Allows multiple entries. Up to 6 months per visit. Return ticket may be requested by border officers. Proof of funds and purpose of visit may be verified. Biometric checks at UK border. Approval within hours to 3 business days.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'argentina' AND destination_slug = 'united-kingdom';

-- United States
UPDATE visa_rules SET visa_type = 'evisa', visa_subtype = 'ESTA', max_stay_days = 90, stay_window_days = null, passport_validity_months = 0, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'ESTA (Electronic System for Travel Authorization) required under Visa Waiver Program (VWP). Not a visa but mandatory pre-travel authorization. Apply at esta.cbp.dhs.gov at least 72 hours before departure. Fee USD 21. Valid 2 years or until passport expiry. Up to 90 days per visit. Cannot be extended. Passport must be e-passport (biometric chip). Return ticket required. Biometric fingerprinting and photo on arrival. CBP officers conduct entry interviews. CRITICAL: Overstaying even 1 day permanently forfeits ESTA eligibility.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'argentina' AND destination_slug = 'united-states';

-- Vietnam
UPDATE visa_rules SET visa_type = 'visa_free', visa_subtype = 'or e-Visa', max_stay_days = 90, stay_window_days = null, passport_validity_months = 6, return_ticket_required = true, insurance_required = false, sufficient_funds_required = true, notes = 'Visa-free under bilateral agreement for tourism or short business stays. Up to 90 days per visit. E-Visa (USD 25) also available at evisa.xuatnhapcanh.gov.vn, valid 90 days, multiple entries. Return ticket may be requested by airline or immigration. Proof of accommodation and sufficient funds may be requested. Entry seamless at Noi Bai (Hanoi), Tan Son Nhat (HCMC), Da Nang, and major ports.', last_verified = '2026-02-19', updated_at = now() WHERE passport_slug = 'argentina' AND destination_slug = 'vietnam';
